scwin.sbm_cntrCnt_submitdone = function (e) {
  // DC20604240061 수입일반 오더 C2
  // ds_cntrInfo
  // ds_cntrCntCrossTab

  // to-do
  // 컨테이너 목록에 있는 값들을 전부 합치는건지 어떤건지 모르겠음. 
  // 아래에 있는 방법으로 안되면 컨테이너 목록에 seq, 중량을 다 합쳐서 넣어야할듯.

  // visible 초기화
  const colCnt = gr_cntrCnt.getTotalCol();
  for (let i = 3; i < colCnt; i++) {
    gr_cntrCnt.setColumnVisible(i, false);
  }
  ;

  // 헤더값 초기화
  const headerCnt = gr_cntrCnt.getTotalHeaderCol();
  for (let i = 0; i < headerCnt; i++) {
    const headerId = gr_cntrCnt.getHeaderID(i);
    if (headerId.includes('keyName')) {
      gr_cntrCnt.setHeaderValue(headerId, '');
    }
  }
  const rawData = dlt_ds_cntrCnt.getAllJSON();
  const uniqueSizes = [...new Set(rawData.map(item => item.cntrSizCd))].sort((a, b) => Number(a) - Number(b));
  const sizeMap = {};
  uniqueSizes.forEach((size, index) => {
    sizeMap[size] = index;
    gr_cntrCnt.setHeaderValue(`keyName${index}`, size);
    gr_cntrCnt.setColumnVisible(`ffCnt${index}`, true);
    gr_cntrCnt.setColumnVisible(`eeCnt${index}`, true);
  });

  // 4. 데이터를 변환합니다.
  const transformedData = Object.values(rawData.reduce((acc, curr) => {
    const type = curr.cntrTypCd;
    const size = curr.cntrSizCd;
    const suffix = sizeMap[size];
    if (!acc[type]) {
      acc[type] = {
        cntrTypCd: type
      };
    }
    ;

    // 데이터 병합
    acc[type][`ffCnt${suffix}`] = curr.ffCnt;
    acc[type][`eeCnt${suffix}`] = curr.eeCnt;
    return acc;
  }, {}));
  ds_cntrCntCrossTab.setJSON(transformedData, false);
};

