// for=gr_cntrInfo event=OnHeadCheckClick(Col,Colid,bCheck)
scwin.gr_cntrInfo_onheaderclick = function (headerId) {
  // 전체 선택 체크 
  let bCheck = gr_cntrInfo.getHeaderValue("chk_header");
  if (headerId == "chk_header") {
    if (bCheck == "1") {
      for (let i = 0; i < ds_cntrInfo.getTotalRow(); i++) {
        if ($c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) {
          ds_cntrInfo.setCellData(i, "chk", 1);
        }
      }
    } else {
      for (let i = 0; i < ds_cntrInfo.getTotalRow(); i++) {
        if ($c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) {
          ds_cntrInfo.setCellData(i, "chk", 0);
        }
      }
    }
  }
};

// for=gr_cntrInfo event=OnDblClick(row,colid)
scwin.gr_cntrInfo_oncelldblclick = function (rowIndex, columnIndex, columnId) {
  if (columnId == "temperCls") {
    for (let i = 0; i < ds_cntrInfo.getTotalRow(); i++) {
      if (!$c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "temper")) && gr_cntrInfo.getReadOnly("grid") == true) {
        ds_cntrInfo.setCellData(i, "temperCls", ds_cntrInfo.getCellData(rowIndex, "temperCls"));
      }
    }
  }
};

