// to-do
// onexit
scwin.gr_cntrInfo_onafteredit = async function (rowIndex, columnIndex, value) {
  // cntrTotalRows.setValue(gr_cntrInfo.getTotalRow())

  let colid = gr_cntrInfo.getColumnID(columnIndex);
  let row = rowIndex;

  //팝업관련
  switch (colid) {
    case "dptWrkPlCd":
      await scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "dptWrkPlCd", "dptWrkPlNm", value, 5, "T", "F");
      break;
    case "arvWrkPlCd":
      await scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "arvWrkPlCd", "arvWrkPlNm", value, 1, "T", "F");
      //수입본선,수입TS인 경우 : TO작업장변경시 같은 bl의 컨테이너번호의 TO작업장도 변경시킴
      let blNo = ds_cntrInfo.getCellData(row, "blNo");
      let arvWrkPlCd = ds_cntrInfo.getCellData(row, "arvWrkPlCd");
      if (arvWrkPlCd != value) {
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR //수입본선
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR //하선지경유TS(부두-->CY)
        ) {
          for (i = 0; i < ds_cntrInfo.getTotalRow(); i++) {
            if (row != i && blNo == ds_cntrInfo.getCellData(i, "blNo")) {
              //blNo가 같은 경우만 해당
              ds_cntrInfo.setCellData(i, "arvWrkPlCd", arvWrkPlCd);
            }
          }
        }
      }
      break;
    case "currPosCd":
      await scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "currPosCd", "currPosNm", value, 2, "T", "F");
      break;
    case "portCd":
      await scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "portCd", "portNm", value, 3, "T", "F");
      ds_cntrInfo.setCellData(row, "destPortCd", ds_cntrInfo.getCellData(row, "portCd"));
      ds_cntrInfo.setCellData(row, "destPortNm", ds_cntrInfo.getCellData(row, "portNm"));
      break;
    case "destPortCd":
      //목적항구
      await scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "destPortCd", "destPortNm", value, 4, "T", "F");
      break;
    case "cntrNo":
      //컨테이너번호
      if (ds_cntrInfo.getCellData(row, colid) == "") {
        //컨테이너정보에 따라서 품명정보의 입력수량 계산하기
        if (ds_cntrInfo.getCellData(row, colid) != value) {
          //f_setCntrInfo(2);								
          //f_calInputQty(); 
        }
      } else {
        if (ds_cntrInfo.getCellData(row, colid) != value) {
          //컨테이너번호 유효성체크
          scwin.f_checkCntrNo(ds_cntrInfo.NameValue(row, colid));
          for (i = 1; i <= ds_cntrInfo.CountRow; i++) {
            if (ds_cntrInfo.getCellData(i, "cntrNo") == ds_cntrInfo.getCellData(row, colid)) {
              if (row != i && ds_cntrInfo.RowStatus(i) != 2) {
                await $c.gus.cfAlertMsg($p, MSG_CM_ERR_031 + MSG_CM_ERR_032, ["컨테이너목록", i, "컨테이너번호"]); //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
                ds_cntrInfo.setCellData(row, "cntrNo", value);
                //gr_cntrInfo.SetColumn("cntrNo");
                return;
              }
            }
          }
          scwin.f_retrieveCntrBasisInfo(ds_cntrInfo.getCellData(row, colid));
        }
        //}
      }
      break;
    case "temper":
      scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, row);
      break;
  }
  ;
};
scwin.f_deleteD = function (e) {};
scwin.f_Import = async function (value) {
  var odrKndCd2 = ed_odrNo.getValue().substring(1, 3);
  if (!(odrKndCd2 == "C1" || odrKndCd2 == "CT")) {
    await $c.win.alert($p, "C1오더, CT오더만 업로드 가능합니다. ");
    return;
  }
  var cntrNoSeq = 0;
  var portSeq = 0;
  var destPortSeq = 0;
  var temperSeq = 0;
  var wtSeq = 0;

  //오더종류에 따라 컨테이너 목록 컬럼이 변경되므로..
  if (odrKndCd2 == "C1") {
    cntrNoSeq = $c.num.parseInt($p, 3);
    portSeq = 9;
    destPortSeq = 10;
    temperSeq = 16;
    wtSeq = 18;
  } else if (odrKndCd2 == "CT") {
    cntrNoSeq = 3;
    portSeq = 10;
    destPortSeq = 11;
    temperSeq = 13;
    wtSeq = 15;
  }
  for (var i = 0; i < ds_excel.getRowCount(); i++) {
    if (ds_excel.getCellData(i, cntrNoSeq).trim() == ds_cntrInfo.getCellData(i, "cntrNo")) {
      await scwin.f_openCommonPopUp(1, ds_excel.getCellData(i, portSeq).trim(), '', 'T', 'T', 'T', i);
      await scwin.f_openCommonPopUp(2, ds_excel.getCellData(i, destPortSeq).trim(), '', 'T', 'T', 'T', i);
      ds_cntrInfo.setCellData(i, "temper", ds_excel.getCellData(i, temperSeq).trim());
      ds_cntrInfo.setCellData(i, "wt", ds_excel.getCellData(i, wtSeq).trim());
    }
    if (i == ds_excel.getTotalRow() - 1) {
      await $c.win.alert($p, "파일업로드가 정상적으로 완료하였습니다. 저장하십시오. ");
    }
  }
  totalRows.setValue(ds_cntrInfo.getRowCount());
  // cfShowTotalRows(totalRows, ds_cntrInfo.get);
  // gr_cntrInfo.ReDraw = "true";
};
scwin.gr_excel_onfilereadend = function () {
  scwin.f_Import();
};
scwin.gr_cntrInfo_oneditkeyup = function (info) {
  event.target.value = info.newValue.toUpperCase();
};
